    Class<?> clazz = obj.getClass();
    if (clazz.isArray()) {
      return measureArraySize(obj, seen);
    }
    long size = NUM_BYTES_OBJECT_HEADER;
    long innerSize = 0L;
    while (clazz != null) {
      final Field[] fields = clazz.getDeclaredFields();
